package com.stockmind.application.factor;
import com.stockmind.application.snapshot.PointInTimeStockSnapshot;import com.stockmind.domain.factor.*;import com.stockmind.domain.market.*;import java.math.*;import java.util.*;
/** Describes price momentum, volatility, liquidity and supplemental market risks. */
public final class MomentumRiskFactorCalculator implements FactorCalculator{
 /** {@inheritDoc} */
 public FactorCategory category(){return FactorCategory.MOMENTUM_RISK;}
 /** Momentum output is descriptive evidence and must not be interpreted as business causality. */
 public FactorCategoryResult calculate(PointInTimeStockSnapshot s){List<MarketBar>b=s.marketHistory().bars();List<MarketBar>idx=s.benchmarkHistory()==null?List.of():s.benchmarkHistory().bars();List<FactorValue>f=new ArrayList<>();for(int n:new int[]{20,60,120,250})add(f,"return_"+n+"d_pct",ret(b,n),"percent",FactorDirection.HIGHER_IS_BETTER,s,"close/latest_n_sessions_close-1");BigDecimal r60=ret(b,60),i60=ret(idx,60),excess=r60==null||i60==null?null:r60.subtract(i60);add(f,"excess_return_vs_csi300_60d_pct",excess,"percent",FactorDirection.HIGHER_IS_BETTER,s,"stock_60d_return-csi300_60d_return");for(int n:new int[]{20,60})add(f,"annualized_volatility_"+n+"d_pct",vol(b,n),"percent",FactorDirection.LOWER_IS_BETTER,s,"stddev(daily_return)*sqrt(252)");for(int n:new int[]{120,250})add(f,"max_drawdown_"+n+"d_pct",drawdown(b,n),"percent",FactorDirection.LOWER_IS_BETTER,s,"min(close/running_peak-1)");add(f,"beta_60d",beta(b,idx,60),"ratio",FactorDirection.NEUTRAL,s,"cov(stock_return,index_return)/var(index_return)");BigDecimal ma20=ma(b,20),ma60=ma(b,60),last=b.isEmpty()?null:b.getLast().close();TrendState state=trend(last,ma20,ma60,r60);BigDecimal vr=volumeRatio(b,20);add(f,"up_down_volume_ratio_20d",vr,"ratio",FactorDirection.HIGHER_IS_BETTER,s,"up_day_volume/down_day_volume");BigDecimal liq=b.stream().skip(Math.max(0,b.size()-20)).map(MarketBar::amount).filter(x->x!=null&&x.signum()>0).reduce(BigDecimal.ZERO,BigDecimal::add);if(liq.signum()>0)liq=liq.divide(BigDecimal.valueOf(Math.min(20,b.size())),8,RoundingMode.HALF_UP);else liq=null;add(f,"average_amount_20d_cny",liq,"CNY",FactorDirection.HIGHER_IS_BETTER,s,"average(last20 amount)");var risk=s.supplementalRisks();List<FactorWarning>w=new ArrayList<>();if(b.size()<120)w.add(FactorWarning.INSUFFICIENT_DATA);addRisk(f,"lockup_release_ratio_next_30d_pct",risk.lockupReleaseRatioNext30d(),s,"scheduled_released_shares/total_shares");addRisk(f,"lockup_release_ratio_next_90d_pct",risk.lockupReleaseRatioNext90d(),s,"scheduled_released_shares/total_shares");addRisk(f,"margin_balance_change_20d_pct",risk.marginBalanceChange20d(),s,"latest_margin_balance/20d_balance-1");addRisk(f,"shareholder_count_change_pct",risk.shareholderCountChangeRatio(),s,"latest_holder_count/prior_holder_count-1");addRisk(f,"block_trade_average_discount_pct",risk.blockTradeAverageDiscountRatio(),s,"average_block_trade_discount");if(risk.lockupReleaseRatioNext90d()!=null&&risk.lockupReleaseRatioNext90d().compareTo(new BigDecimal("0.05"))>0)w.add(FactorWarning.UPCOMING_LOCKUP_RELEASE);if(risk.marginBalanceChange20d()!=null&&risk.marginBalanceChange20d().compareTo(new BigDecimal("0.20"))>0)w.add(FactorWarning.MARGIN_CROWDING_RISING);if(risk.shareholderCountChangeRatio()!=null&&risk.shareholderCountChangeRatio().compareTo(new BigDecimal("0.10"))>0)w.add(FactorWarning.SHAREHOLDER_DISPERSION_RISING);if(risk.blockTradeAverageDiscountRatio()!=null&&risk.blockTradeAverageDiscountRatio().compareTo(new BigDecimal("-0.05"))<0)w.add(FactorWarning.BLOCK_TRADE_DISCOUNT);return FactorSupport.result(category(),f,w,List.of("trend_state="+state));}
 private BigDecimal ret(List<MarketBar>b,int n){if(b.size()<=n)return null;return FactorSupport.div(b.getLast().close(),b.get(b.size()-1-n).close()).subtract(BigDecimal.ONE);}private BigDecimal vol(List<MarketBar>b,int n){List<Double>r=returns(b,n);if(r.size()<2)return null;double m=r.stream().mapToDouble(x->x).average().orElse(0),v=r.stream().mapToDouble(x->Math.pow(x-m,2)).sum()/(r.size()-1);return BigDecimal.valueOf(Math.sqrt(v)*Math.sqrt(252));}private BigDecimal drawdown(List<MarketBar>b,int n){if(b.isEmpty())return null;int start=Math.max(0,b.size()-n);BigDecimal peak=null,min=BigDecimal.ZERO;for(var x:b.subList(start,b.size())){if(peak==null||x.close().compareTo(peak)>0)peak=x.close();BigDecimal d=FactorSupport.div(x.close(),peak).subtract(BigDecimal.ONE);if(d.compareTo(min)<0)min=d;}return min;}
 private BigDecimal beta(List<MarketBar>a,List<MarketBar>i,int n){List<Double>x=returns(a,n),y=returns(i,n);int m=Math.min(x.size(),y.size());if(m<20)return null;x=x.subList(x.size()-m,x.size());y=y.subList(y.size()-m,y.size());double mx=x.stream().mapToDouble(v->v).average().orElse(0),my=y.stream().mapToDouble(v->v).average().orElse(0),cov=0,var=0;for(int k=0;k<m;k++){cov+=(x.get(k)-mx)*(y.get(k)-my);var+=Math.pow(y.get(k)-my,2);}return var==0?null:BigDecimal.valueOf(cov/var);}private List<Double>returns(List<MarketBar>b,int n){int start=Math.max(1,b.size()-n);List<Double>r=new ArrayList<>();for(int k=start;k<b.size();k++)r.add(b.get(k).close().divide(b.get(k-1).close(),12,RoundingMode.HALF_UP).doubleValue()-1);return r;}private BigDecimal ma(List<MarketBar>b,int n){if(b.size()<n)return null;return b.subList(b.size()-n,b.size()).stream().map(MarketBar::close).reduce(BigDecimal.ZERO,BigDecimal::add).divide(BigDecimal.valueOf(n),8,RoundingMode.HALF_UP);}private TrendState trend(BigDecimal l,BigDecimal m20,BigDecimal m60,BigDecimal r){if(l==null||m20==null||m60==null)return TrendState.RANGE_BOUND;if(l.compareTo(m20)>0&&m20.compareTo(m60)>0)return r!=null&&r.compareTo(new BigDecimal("0.15"))>0?TrendState.STRONG_UPTREND:TrendState.UPTREND;if(l.compareTo(m20)<0&&m20.compareTo(m60)<0)return r!=null&&r.compareTo(new BigDecimal("-0.15"))<0?TrendState.STRONG_DOWNTREND:TrendState.DOWNTREND;return TrendState.RANGE_BOUND;}private BigDecimal volumeRatio(List<MarketBar>b,int n){BigDecimal up=BigDecimal.ZERO,down=BigDecimal.ZERO;int start=Math.max(1,b.size()-n);for(int k=start;k<b.size();k++){if(b.get(k).close().compareTo(b.get(k-1).close())>=0)up=up.add(b.get(k).volume());else down=down.add(b.get(k).volume());}return FactorSupport.div(up,down);}private void add(List<FactorValue>f,String n,BigDecimal v,String unit,FactorDirection d,PointInTimeStockSnapshot s,String formula){f.add(v==null?FactorSupport.missing(n,unit,d,s,formula,"历史序列长度或字段不足"):FactorSupport.value(n,"percent".equals(unit)?FactorSupport.pct(v):v,v,unit,d,s,s.marketPrice().effectiveTradeDate(),List.of("tencent_adjusted_daily_bars"),formula,FactorQuality.VALID,List.of(),""));}
 private void addRisk(List<FactorValue>f,String n,BigDecimal v,PointInTimeStockSnapshot s,String formula){f.add(FactorSupport.value(n,FactorSupport.pct(v),v,"percent",FactorDirection.LOWER_IS_BETTER,s,null,s.supplementalRisks().sources(),formula,v==null?FactorQuality.MISSING:FactorQuality.VALID,List.of(),v==null?String.join(",",s.supplementalRisks().limitations()):""));}
}
